input.command:
PLUGIN_ROOT="/home/cwtrocks/.claude/plugins/cache/understand-anything/understand-anything/2.7.6"
PROJECT_ROOT="/home/cwtrocks/OpenCoreAnalysisKit"

# Build the input JSON for extract-import-map.mjs from the files array
node -e "
const fs = require('fs');
const scan = JSON.parse(fs.readFileSync('$PROJECT_ROOT/.understand-anything/tmp/ua-scan-files.json', 'utf8'));
const input = {
  projectRoot: '$PROJECT_ROOT',
  files: scan.files.map(f => ({ path: f.path, language: f.language, fileCategory: f.fileCategory }))
};
fs.writeFileSync('$PROJECT_ROOT/.understand-anything/tmp/ua-import-map-input.json', JSON.stringify(input));
console.log('Input written, files:', input.files.length);
" 2>&1

node -e '
const fs = require("fs");
const scan = JSON.parse(fs.readFileSync("/home/cwtrocks/OpenCoreAnalysisKit/.understand-anything/tmp/ua-scan-files.json", "utf8"));
const importMapOutput = JSON.parse(fs.readFileSync("/home/cwtrocks/OpenCoreAnalysisKit/.understand-anything/tmp/ua-import-map-output.json", "utf8"));

// Narrative fields synthesized from Step A
const result = {
  name: "OpenCoreAnalysisKit",
  description: "A C++ tool for analyzing Android coredumps and tombstones. It parses ELF core files and provides REPL commands to inspect Java heap objects, ART runtime state, threads, and memory regions. Supports Android SDK 21-37 across arm64, arm, x86_64, x86, and riscv64 architectures.",
  languages: ["c", "cmake", "config", "cpp", "db", "html", "javascript", "json", "mdb", "markdown", "python", "shell", "txt", "unknown", "yaml"],
  frameworks: ["Capstone", "XZ Utils", "Zstd", "cpp-httplib", "GitHub Actions"],
  files: scan.files,
  totalFiles: scan.totalFiles,
  filteredByIgnore: scan.filteredByIgnore,
  estimatedComplexity: scan.estimatedComplexity,
  importMap: importMapOutput.importMap
};

fs.writeFileSync("/home/cwtrocks/OpenCoreAnalysisKit/.understand-anything/intermediate/scan-result.json", JSON.stringify(result, null, 2));
console.log("Written, totalFiles:", result.totalFiles, "languages:", result.languages.length, "frameworks:", result.frameworks.length);
' 2>&1

node -e '
const fs = require("fs");
const r = JSON.parse(fs.readFileSync("/home/cwtrocks/OpenCoreAnalysisKit/.understand-anything/intermediate/scan-result.json", "utf8"));
console.log("name:", r.name);
console.log("totalFiles:", r.totalFiles);
console.log("files.length:", r.files.length);
console.log("importMap entries:", Object.keys(r.importMap).length);
console.log("complexity:", r.estimatedComplexity);
console.log("languages:", r.languages.join(", "));
console.log("frameworks:", r.frameworks.join(", "));
' 2>&1
